# AI Usage: this function was generated by ChatGPT
# also, I asked the AI some questions about what certain parts of the code do, such as
# what model.eval() does (so I can understand it better)
def compute_auc(model, val_loader, device=device):
    model.eval()
    torch.set_grad_enabled(False)

    all_probs = []
    all_labels = []

    for images, labels in tqdm(val_loader):
        images = images.to(device)
        # labels are initially [B, 1] where B is batch size
        # squeeze to [B]
        labels = labels.to(device).squeeze(1).long()

        outputs = model(images)
        probs = torch.softmax(outputs, dim=1)

        all_probs.append(probs.detach().cpu().numpy())
        all_labels.append(labels.detach().cpu().numpy())

    all_probs = np.concatenate(all_probs, axis=0) # shape: [N, num_classes]
    all_labels = np.concatenate(all_labels, axis=0) # shape [N]

    # multi-class macro AUC, one-vs-rest
    auc = roc_auc_score(
        all_labels,
        all_probs,
        multi_class="ovr",
        average="macro"
    )

    torch.set_grad_enabled(True)
    return float(auc)

# AI Usage: This function was generated by ChatGPT to look at per-class accuracy and AUC
def evaluate_model(model, loader, criterion, num_classes, device=device):
    model.eval()
    torch.set_grad_enabled(False)

    epoch_loss = 0.0
    correct = 0
    total = 0

    all_labels = []
    all_preds = []
    all_probs = []

    for images, labels in tqdm(loader):
        images = images.to(device)
        labels = labels.to(device).squeeze(1).long()  # [B,1] -> [B]

        with torch.no_grad():
            outputs = model(images)
            loss = criterion(outputs, labels)
            probs = torch.softmax(outputs, dim=1)

        # loss / accuracy aggregates
        batch_size = images.size(0)
        epoch_loss += loss.item() * batch_size

        pred_labels = outputs.argmax(dim=1)
        correct += (pred_labels == labels).sum().item()
        total += batch_size

        # store for per-class metrics & AUC
        all_labels.append(labels.cpu().numpy())
        all_preds.append(pred_labels.cpu().numpy())
        all_probs.append(probs.cpu().numpy())

    avg_loss = epoch_loss / len(loader.dataset)
    overall_acc = correct / total if total > 0 else 0.0

    # concat all batches
    all_labels = np.concatenate(all_labels, axis=0)   # [N]
    all_preds = np.concatenate(all_preds, axis=0)     # [N]
    all_probs = np.concatenate(all_probs, axis=0)     # [N, num_classes]

    # ---------- per-class accuracy (recall) ----------
    # acc_c = (# samples of class c predicted correctly) / (# samples of class c)
    per_class_acc = np.zeros(num_classes, dtype=np.float64)
    for c in range(num_classes):
        mask = (all_labels == c)
        if mask.sum() == 0:
            per_class_acc[c] = np.nan  # no samples of this class
        else:
            per_class_acc[c] = (all_preds[mask] == c).mean()

    # ---------- AUCs ----------
    # macro AUC (same as your compute_auc)
    macro_auc = roc_auc_score(
        all_labels,
        all_probs,
        multi_class="ovr",
        average="macro"
    )

    # per-class AUCs (one-vs-rest)
    per_class_auc = roc_auc_score(
        all_labels,
        all_probs,
        multi_class="ovr",
        average=None
    )  # shape: [num_classes]

    torch.set_grad_enabled(True)

    metrics = {
        "loss": float(avg_loss),
        "overall_acc": float(overall_acc),
        "macro_auc": float(macro_auc),
        "per_class_acc": per_class_acc,   # numpy array length = num_classes
        "per_class_auc": per_class_auc,   # numpy array length = num_classes
    }
    return metrics
